import json
import pickle
import zipfile
import struct
from functools import reduce
from operator import mul

pth='/app/model.pth'
out='/app/weights.json'

class FloatStorage:  # placeholder for pickle GLOBAL torch FloatStorage
    pass

class StorageRef:
    __slots__=('key','size')
    def __init__(self,key,size):
        self.key=key
        self.size=size

class TensorRef:
    __slots__=('storage','storage_offset','size','stride')
    def __init__(self,storage,storage_offset,size,stride):
        self.storage=storage
        self.storage_offset=storage_offset
        self.size=tuple(size)
        self.stride=tuple(stride)


def rebuild_tensor_v2(storage, storage_offset, size, stride, requires_grad, backward_hooks):
    return TensorRef(storage, storage_offset, size, stride)

class TorchUnpickler(pickle.Unpickler):
    def find_class(self, module, name):
        if module == 'torch._utils' and name == '_rebuild_tensor_v2':
            return rebuild_tensor_v2
        if module == 'torch' and name == 'FloatStorage':
            return FloatStorage
        return super().find_class(module, name)

    def persistent_load(self, pid):
        # ('storage', StorageType, key, location, size)
        if not isinstance(pid, tuple) or len(pid) != 5 or pid[0] != 'storage':
            raise pickle.UnpicklingError(f'Unsupported persistent id: {pid!r}')
        _kind, _storage_type, key, _location, size = pid
        return StorageRef(key, size)


def tensor_to_nested_list(tensor, storage):
    size = tensor.size
    stride = tensor.stride
    offset = tensor.storage_offset

    if len(size) == 0:
        return storage[offset]

    def rec(dim, base_idx):
        if dim == len(size):
            return storage[base_idx]
        arr = []
        for i in range(size[dim]):
            arr.append(rec(dim + 1, base_idx + i * stride[dim]))
        return arr

    return rec(0, offset)

with zipfile.ZipFile(pth) as z:
    base='simple_mnist/'
    byteorder = z.read(base+'byteorder').decode('utf-8').strip()
    if byteorder not in ('little','big'):
        raise RuntimeError('Unknown byteorder')
    endian = '<' if byteorder == 'little' else '>'

    state = TorchUnpickler(z.open(base+'data.pkl')).load()

    storages = {}
    for name, tensor in state.items():
        key = tensor.storage.key
        if key not in storages:
            raw = z.read(base + 'data/' + key)
            n = len(raw) // 4
            fmt = endian + f'{n}f'
            vals = list(struct.unpack(fmt, raw))
            storages[key] = vals

model = {
    'input_dim': 784,
    'hidden_dim': 16,
    'num_classes': 10,
    'input_layer': {
        'weight': tensor_to_nested_list(state['input_layer.weight'], storages[state['input_layer.weight'].storage.key]),
        'bias': tensor_to_nested_list(state['input_layer.bias'], storages[state['input_layer.bias'].storage.key]),
    },
    'hidden_layer': {
        'weight': tensor_to_nested_list(state['hidden_layer.weight'], storages[state['hidden_layer.weight'].storage.key]),
        'bias': tensor_to_nested_list(state['hidden_layer.bias'], storages[state['hidden_layer.bias'].storage.key]),
    },
    'output_layer': {
        'weight': tensor_to_nested_list(state['output_layer.weight'], storages[state['output_layer.weight'].storage.key]),
