#include <algorithm>
#include <cmath>
#include <cstdio>
#include <fstream>
#include <iostream>
#include <numeric>
#include <sstream>
#include <string>
#include <vector>

#include "lodepng.h"

extern "C" {
#include "cJSON.h"
}

struct Model {
    int input_dim = 0;
    int hidden_dim = 0;
    int num_classes = 0;

    std::vector<float> w1;  // hidden_dim x input_dim
    std::vector<float> b1;  // hidden_dim
    std::vector<float> w2;  // hidden_dim x hidden_dim
    std::vector<float> b2;  // hidden_dim
    std::vector<float> w3;  // num_classes x hidden_dim
    std::vector<float> b3;  // num_classes
};

static bool read_file(const std::string &path, std::string &out, std::string &err) {
    std::ifstream file(path, std::ios::binary);
    if (!file) {
        err = "failed to open file: " + path;
        return false;
    }
    std::ostringstream ss;
    ss << file.rdbuf();
    out = ss.str();
    return true;
}

static bool parse_vector(cJSON *array, int expected_size, std::vector<float> &out, std::string &err) {
    if (!cJSON_IsArray(array)) {
        err = "expected JSON array";
        return false;
    }
    const int n = cJSON_GetArraySize(array);
    if (n != expected_size) {
        err = "unexpected vector size";
        return false;
    }
    out.resize(expected_size);
    for (int i = 0; i < expected_size; ++i) {
        cJSON *item = cJSON_GetArrayItem(array, i);
        if (!cJSON_IsNumber(item)) {
            err = "vector entry is not a number";
            return false;
        }
        out[i] = static_cast<float>(item->valuedouble);
    }
    return true;
}

static bool parse_matrix(cJSON *array, int rows, int cols, std::vector<float> &out, std::string &err) {
    if (!cJSON_IsArray(array)) {
        err = "expected matrix array";
        return false;
    }
    if (cJSON_GetArraySize(array) != rows) {
        err = "unexpected matrix row count";
        return false;
    }

    out.resize(static_cast<size_t>(rows) * static_cast<size_t>(cols));
    for (int r = 0; r < rows; ++r) {
        cJSON *row = cJSON_GetArrayItem(array, r);
        if (!cJSON_IsArray(row) || cJSON_GetArraySize(row) != cols) {
            err = "unexpected matrix column count";
            return false;
        }
        for (int c = 0; c < cols; ++c) {
            cJSON *item = cJSON_GetArrayItem(row, c);
            if (!cJSON_IsNumber(item)) {
                err = "matrix entry is not a number";
                return false;
            }
            out[static_cast<size_t>(r) * cols + c] = static_cast<float>(item->valuedouble);
        }
    }

    return true;
}

static bool load_model(const std::string &weights_path, Model &model, std::string &err) {
    std::string json_text;
    if (!read_file(weights_path, json_text, err)) {
        return false;
    }

    cJSON *root = cJSON_Parse(json_text.c_str());
    if (!root) {
        err = "failed to parse JSON";
        return false;
    }

    auto cleanup = [&]() { cJSON_Delete(root); };

    cJSON *input_dim = cJSON_GetObjectItemCaseSensitive(root, "input_dim");
    cJSON *hidden_dim = cJSON_GetObjectItemCaseSensitive(root, "hidden_dim");
    cJSON *num_classes = cJSON_GetObjectItemCaseSensitive(root, "num_classes");

    if (!cJSON_IsNumber(input_dim) || !cJSON_IsNumber(hidden_dim) || !cJSON_IsNumber(num_classes)) {
        err = "missing model dimensions";
        cleanup();
        return false;
    }

    model.input_dim = input_dim->valueint;
    model.hidden_dim = hidden_dim->valueint;
    model.num_classes = num_classes->valueint;

    cJSON *input_layer = cJSON_GetObjectItemCaseSensitive(root, "input_layer");
    cJSON *hidden_layer = cJSON_GetObjectItemCaseSensitive(root, "hidden_layer");
    cJSON *output_layer = cJSON_GetObjectItemCaseSensitive(root, "output_layer");

    if (!cJSON_IsObject(input_layer) || !cJSON_IsObject(hidden_layer) || !cJSON_IsObject(output_layer)) {
        err = "missing model layers";
        cleanup();
        return false;
    }

    if (!parse_matrix(cJSON_GetObjectItemCaseSensitive(input_layer, "weight"), model.hidden_dim, model.input_dim,
                      model.w1, err) ||
        !parse_vector(cJSON_GetObjectItemCaseSensitive(input_layer, "bias"), model.hidden_dim, model.b1, err) ||
        !parse_matrix(cJSON_GetObjectItemCaseSensitive(hidden_layer, "weight"), model.hidden_dim, model.hidden_dim,
                      model.w2, err) ||
        !parse_vector(cJSON_GetObjectItemCaseSensitive(hidden_layer, "bias"), model.hidden_dim, model.b2, err) ||
        !parse_matrix(cJSON_GetObjectItemCaseSensitive(output_layer, "weight"), model.num_classes, model.hidden_dim,
                      model.w3, err) ||
        !parse_vector(cJSON_GetObjectItemCaseSensitive(output_layer, "bias"), model.num_classes, model.b3, err)) {
        cleanup();
        return false;
    }

    cleanup();
    return true;
}

static bool load_mnist_image(const std::string &image_path, int expected_input_dim, std::vector<float> &pixels,
                             std::string &err) {
    std::vector<unsigned char> rgba;
    unsigned width = 0;
    unsigned height = 0;

    unsigned decode_error = lodepng::decode(rgba, width, height, image_path);
    if (decode_error != 0) {
        err = "failed to decode PNG";
        return false;
    }

    if (expected_input_dim != static_cast<int>(width * height)) {
        err = "image size does not match model input";
        return false;
    }

    pixels.resize(width * height);
    for (size_t i = 0; i < pixels.size(); ++i) {
        const float r = static_cast<float>(rgba[i * 4 + 0]);
        const float g = static_cast<float>(rgba[i * 4 + 1]);
        const float b = static_cast<float>(rgba[i * 4 + 2]);
        const float a = static_cast<float>(rgba[i * 4 + 3]) / 255.0f;

        float gray = (0.299f * r + 0.587f * g + 0.114f * b) / 255.0f;
        // If alpha is present, blend with black background (MNIST style).
        gray *= a;

        pixels[i] = gray;
    }

    // Handle inverted images (white background / dark digit) automatically.
    const float mean = std::accumulate(pixels.begin(), pixels.end(), 0.0f) / static_cast<float>(pixels.size());
    if (mean > 0.5f) {
        for (float &v : pixels) {
            v = 1.0f - v;
        }
    }

    return true;
}

static int argmax(const std::vector<float> &v) {
    int best_idx = 0;
    float best_val = v[0];
    for (int i = 1; i < static_cast<int>(v.size()); ++i) {
        if (v[i] > best_val) {
            best_val = v[i];
            best_idx = i;
        }
    }
    return best_idx;
}

static int predict_digit(const Model &m, const std::vector<float> &x) {
    std::vector<float> h1(static_cast<size_t>(m.hidden_dim), 0.0f);
    std::vector<float> h2(static_cast<size_t>(m.hidden_dim), 0.0f);
    std::vector<float> out(static_cast<size_t>(m.num_classes), 0.0f);

    for (int i = 0; i < m.hidden_dim; ++i) {
        float acc = m.b1[i];
        const size_t row = static_cast<size_t>(i) * m.input_dim;
        for (int j = 0; j < m.input_dim; ++j) {
            acc += m.w1[row + j] * x[j];
        }
        h1[i] = std::max(0.0f, acc);
    }

    for (int i = 0; i < m.hidden_dim; ++i) {
        float acc = m.b2[i];
        const size_t row = static_cast<size_t>(i) * m.hidden_dim;
        for (int j = 0; j < m.hidden_dim; ++j) {
            acc += m.w2[row + j] * h1[j];
        }
        h2[i] = std::max(0.0f, acc);
    }

    for (int i = 0; i < m.num_classes; ++i) {
        float acc = m.b3[i];
        const size_t row = static_cast<size_t>(i) * m.hidden_dim;
        for (int j = 0; j < m.hidden_dim; ++j) {
            acc += m.w3[row + j] * h2[j];
        }
        out[i] = acc;
    }

    return argmax(out);
}

int main(int argc, char **argv) {
    if (argc != 3) {
        std::fprintf(stderr, "Usage: %s weights.json image.png\n", argv[0]);
        return 1;
    }

    const std::string weights_path = argv[1];
    const std::string image_path = argv[2];

    Model model;
    std::string err;
    if (!load_model(weights_path, model, err)) {
        std::fprintf(stderr, "Error loading weights: %s\n", err.c_str());
        return 1;
    }

    std::vector<float> pixels;
    if (!load_mnist_image(image_path, model.input_dim, pixels, err)) {
        std::fprintf(stderr, "Error loading image: %s\n", err.c_str());
        return 1;
    }

    const int digit = predict_digit(model, pixels);
    std::cout << digit;
    return 0;
}
