#!/usr/bin/env python3
import json
import struct
import sys
import zlib


PNG_SIGNATURE = b"\x89PNG\r\n\x1a\n"


def paeth_predictor(a: int, b: int, c: int) -> int:
    p = a + b - c
    pa = abs(p - a)
    pb = abs(p - b)
    pc = abs(p - c)
    if pa <= pb and pa <= pc:
        return a
    if pb <= pc:
        return b
    return c


def decode_png(path: str):
    with open(path, "rb") as f:
        data = f.read()

    if len(data) < 8 or data[:8] != PNG_SIGNATURE:
        raise ValueError("invalid PNG signature")

    pos = 8
    width = height = None
    bit_depth = color_type = interlace = None
    palette = None
    trns = None
    idat = bytearray()

    while pos + 8 <= len(data):
        length = struct.unpack(">I", data[pos : pos + 4])[0]
        pos += 4
        ctype = data[pos : pos + 4]
        pos += 4
        if pos + length + 4 > len(data):
            raise ValueError("corrupt PNG chunk")
        chunk = data[pos : pos + length]
        pos += length
        _crc = data[pos : pos + 4]
        pos += 4

        if ctype == b"IHDR":
            if length != 13:
                raise ValueError("invalid IHDR")
            width, height, bit_depth, color_type, compression, filt, interlace = struct.unpack(">IIBBBBB", chunk
            )
            if compression != 0 or filt != 0:
                raise ValueError("unsupported PNG compression/filter")
            if interlace != 0:
                raise ValueError("interlaced PNG not supported")
            if bit_depth != 8:
                raise ValueError("only 8-bit PNG supported")
        elif ctype == b"PLTE":
            if length % 3 != 0:
                raise ValueError("invalid PLTE")
            palette = chunk
        elif ctype == b"tRNS":
            trns = chunk
        elif ctype == b"IDAT":
            idat.extend(chunk)
        elif ctype == b"IEND":
            break

    if width is None or height is None:
        raise ValueError("missing IHDR")

    channels_by_color_type = {0: 1, 2: 3, 3: 1, 4: 2, 6: 4}
    if color_type not in channels_by_color_type:
        raise ValueError("unsupported color type")

    channels = channels_by_color_type[color_type]
    bpp = channels
    stride = width * bpp

    raw = zlib.decompress(bytes(idat))
    expected_len = (stride + 1) * height
    if len(raw) != expected_len:
        raise ValueError("unexpected decompressed length")

    recon = bytearray(stride * height)
    src = 0
    dst = 0

    for _ in range(height):
        ftype = raw[src]
        src += 1
        cur = bytearray(raw[src : src + stride])
        src += stride

        if ftype == 0:
            pass
        elif ftype == 1:
            for i in range(stride):
                left = cur[i - bpp] if i >= bpp else 0
                cur[i] = (cur[i] + left) & 0xFF
        elif ftype == 2:
            for i in range(stride):
                up = recon[dst - stride + i] if dst >= stride else 0
                cur[i] = (cur[i] + up) & 0xFF
        elif ftype == 3:
            for i in range(stride):
                left = cur[i - bpp] if i >= bpp else 0
                up = recon[dst - stride + i] if dst >= stride else 0
                cur[i] = (cur[i] + ((left + up) // 2)) & 0xFF
        elif ftype == 4:
            for i in range(stride):
                left = cur[i - bpp] if i >= bpp else 0
                up = recon[dst - stride + i] if dst >= stride else 0
                up_left = recon[dst - stride + i - bpp] if (dst >= stride and i >= bpp) else 0
                cur[i] = (cur[i] + paeth_predictor(left, up, up_left)) & 0xFF
        else:
            raise ValueError("unsupported filter type")

        recon[dst : dst + stride] = cur
        dst += stride

    pixels = []
    idx = 0

    if color_type == 0:
        for _ in range(width * height):
            g = recon[idx]
            idx += 1
            pixels.append(g / 255.0)
    elif color_type == 2:
        for _ in range(width * height):
            r = recon[idx]
            g = recon[idx + 1]
            b = recon[idx + 2]
            idx += 3
            pixels.append((0.299 * r + 0.587 * g + 0.114 * b) / 255.0)
    elif color_type == 3:
        if palette is None:
            raise ValueError("indexed PNG missing palette")
        pal_count = len(palette) // 3
        alpha = [255] * pal_count
        if trns is not None:
            for i, a in enumerate(trns[:pal_count]):
                alpha[i] = a
        for _ in range(width * height):
            p = recon[idx]
            idx += 1
            if p >= pal_count:
                raise ValueError("palette index out of range")
            r = palette[p * 3]
            g = palette[p * 3 + 1]
            b = palette[p * 3 + 2]
            a = alpha[p] / 255.0
            pixels.append(((0.299 * r + 0.587 * g + 0.114 * b) / 255.0) * a)
    elif color_type == 4:
        for _ in range(width * height):
            g = recon[idx]
            a = recon[idx + 1] / 255.0
            idx += 2
            pixels.append((g / 255.0) * a)
    elif color_type == 6:
        for _ in range(width * height):
            r = recon[idx]
            g = recon[idx + 1]
            b = recon[idx + 2]
            a = recon[idx + 3] / 255.0
            idx += 4
            pixels.append(((0.299 * r + 0.587 * g + 0.114 * b) / 255.0) * a)

    return width, height, pixels


def relu(x: float) -> float:
    return x if x > 0.0 else 0.0


def predict(weights, image_pixels):
    input_dim = int(weights["input_dim"])
    hidden_dim = int(weights["hidden_dim"])
    num_classes = int(weights["num_classes"])

    if len(image_pixels) != input_dim:
        raise ValueError("image size does not match model input")

    mean = sum(image_pixels) / len(image_pixels)
    if mean > 0.5:
        image_pixels = [1.0 - x for x in image_pixels]

    w1 = weights["input_layer"]["weight"]
    b1 = weights["input_layer"]["bias"]
    w2 = weights["hidden_layer"]["weight"]
    b2 = weights["hidden_layer"]["bias"]
    w3 = weights["output_layer"]["weight"]
    b3 = weights["output_layer"]["bias"]

    h1 = [0.0] * hidden_dim
    for i in range(hidden_dim):
        acc = float(b1[i])
        row = w1[i]
        for j in range(input_dim):
            acc += float(row[j]) * image_pixels[j]
        h1[i] = relu(acc)

    h2 = [0.0] * hidden_dim
    for i in range(hidden_dim):
        acc = float(b2[i])
        row = w2[i]
        for j in range(hidden_dim):
            acc += float(row[j]) * h1[j]
        h2[i] = relu(acc)

    logits = [0.0] * num_classes
    for i in range(num_classes):
        acc = float(b3[i])
        row = w3[i]
        for j in range(hidden_dim):
            acc += float(row[j]) * h2[j]
        logits[i] = acc

    best_idx = 0
    best_val = logits[0]
    for i in range(1, num_classes):
        if logits[i] > best_val:
            best_val = logits[i]
            best_idx = i
    return best_idx


def main():
    if len(sys.argv) != 3:
        print(f"Usage: {sys.argv[0]} weights.json image.png", file=sys.stderr)
        return 1

    weights_path = sys.argv[1]
    image_path = sys.argv[2]

    try:
        with open(weights_path, "r", encoding="utf-8") as f:
            weights = json.load(f)
        _w, _h, pixels = decode_png(image_path)
        digit = predict(weights, pixels)
    except Exception as e:
        print(str(e), file=sys.stderr)
        return 1

    sys.stdout.write(str(digit))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
